package com.eas.ui.user;
import com.eas.config.Database; import com.eas.model.UserSession; import com.eas.util.*; import java.awt.*; import java.sql.*; import javax.swing.*;
public class NotificationPanel extends UserTablePanel { public NotificationPanel(UserSession s){super(s,"My Notifications","SELECT id,title,message_body,notification_type,created_at,read_status FROM notifications WHERE user_id=? ORDER BY id DESC","SELECT id,title,message_body,notification_type,created_at,read_status FROM notifications WHERE user_id=? AND (title LIKE ? OR message_body LIKE ? OR notification_type LIKE ?) ORDER BY id DESC",true);JPanel p=new JPanel();JButton mark=UITheme.button("MARK SELECTED READ");p.add(mark);add(p,BorderLayout.SOUTH);mark.addActionListener(e->mark());}private void mark(){int r=table.getSelectedRow();if(r<0)return;try(Connection c=Database.getConnection();PreparedStatement p=c.prepareStatement("UPDATE notifications SET read_status='READ' WHERE id=? AND user_id=?")){p.setInt(1,Integer.parseInt(table.getValueAt(r,0).toString()));p.setInt(2,session.getId());p.executeUpdate();load("");}catch(Exception ex){Dialogs.error(this,ex.getMessage());}} }
